// ---------------------------------------------------------------------------
// Build ReportProps from EEG results
// ---------------------------------------------------------------------------

function buildReportProps(
  result: ReportResult,
  subject: SubjectInfo,
  startTime: Date | null,
  deviceId: string | null,
  rppg?: RppgResults,
  lang: ReportLang = 'zh-TW',
): ReportProps {
  const RT = REPORT_TEXT[lang];
  const pad2 = (n: number) => String(n).padStart(2, '0');
  const now = new Date();
  const rec = startTime ?? now;

  const indices = result.indices as unknown as Record<string, number>;
  const tscores = result.tscores as unknown as Record<string, number>;

  const ORDER = ['TBR', 'APR', 'FAA', 'PAF', 'RSA', 'COH', 'EnTP'];

  const brainIndices = ORDER.map(key => {
    const info  = INDEX_INFO[key]!;
    const raw   = indices[key] ?? 0;
    const ts    = tscores[key] ?? 50;
    const tier  = getTier(ts);
    const isHigh = tier === 'high' || tier === 'vhigh';
    const isLow  = tier === 'low'  || tier === 'vlow';
    const showRec = isHigh || isLow;
    const recDir  = isHigh ? 'high' : 'low';
    const recs    = RECS[key]?.[recDir];
    const valueStr = info.unit
      ? `${raw.toFixed(info.decimals)} ${info.unit}`
      : raw.toFixed(info.decimals);
    return {
      id:          key,
      name:        `${RT.indexName[key] ?? info.chName} (${key})`,
      value:       valueStr,
      tScore:      ts,
      status:      tierStatusLabel(ts, lang),
      description: RT.tierDesc[key]?.[tier] ?? '',
      supplements: recs?.supps ?? [],
      bachFlowers: recs?.flowers ?? [],
      activities:  showRec ? (RT.activityRecs[key]?.[recDir] ?? []) : [],
      showRec,
    };
  });

  // Summary
  const abnormal = brainIndices.filter(b => b.tScore < 30 || b.tScore > 70);
  const good     = brainIndices.filter(b => b.tScore >= 40 && b.tScore <= 60);

  // Capability
  const capEntries = Object.entries(result.capability ?? {});
  const capabilityProfile = capEntries
    .sort((a, b) => b[1] - a[1])
    .map(([label, score], i) => ({
      label,
      value: Math.round(score * 10) / 10,
      color: CAP_COLORS[i % CAP_COLORS.length]!,
    }));

  const ageNotApplicable = result.age < 7;
  const ageGroupLabel =
    result.age >= 65 ? RT.ageGroupSenior :
    result.age >= 25 ? RT.ageGroupAdult :
    RT.ageGroupStudent;

  // For age < 7: show student-group labels without scores
  const STUDENT_LABELS: string[] = RT.studentLabels;
  const effectiveCapability = ageNotApplicable
    ? STUDENT_LABELS.map((label, i) => ({ label, value: 0, color: CAP_COLORS[i % CAP_COLORS.length]! }))
    : capabilityProfile;

  // Top supplements & flowers — collect from ALL abnormal indicators, deduplicate by name
  const seenSupps   = new Set<string>();
  const seenFlowers = new Set<string>();
  const topSupps:   { name: string; desc: string }[] = [];
  const topFlowers: { name: string; desc: string }[] = [];

  abnormal.forEach(idx => {
    const dir = (idx.tScore < 30 || getTier(idx.tScore) === 'vlow') ? 'low' : 'high';
    const recs = RECS[idx.id]?.[dir];
    if (recs) {
      recs.supps.forEach(s => {
        // Strip dosage (everything from first digit onward), keep only supplement type name
        const nameOnly = s.replace(/\s+[\d\.，,].*/u, '').trim();
        const key = nameOnly || s;
        if (!seenSupps.has(key) && topSupps.length < 6) {
          seenSupps.add(key);
          topSupps.push({ name: key, desc: '' });
        }
      });
      recs.flowers.forEach(f => {
        const paren = f.indexOf('（');
        const key   = paren > 0 ? f.slice(0, paren) : f;
        if (!seenFlowers.has(key) && topFlowers.length < 6) {
          seenFlowers.add(key);
          topFlowers.push({
            name: key,
            desc: paren > 0 ? f.slice(paren + 1).replace('）', '') : RT.flowerDescFallback,
          });
        }
      });
    }
  });

  // Fallback if no abnormal
  if (topSupps.length === 0)   topSupps.push(RT.fallbackSupp);
  if (topFlowers.length === 0) topFlowers.push(RT.fallbackFlower);

  // Auto-generate report ID: RPT-YYYYMMDD-XXXX
  const rptDate = `${now.getFullYear()}${pad2(now.getMonth()+1)}${pad2(now.getDate())}`;
  const rptRnd  = Math.random().toString(36).slice(2, 6).toUpperCase();
  const reportId = `RPT-${rptDate}-${rptRnd}`;

  const sexLabel = subject.sex === 'M' ? RT.sexM : subject.sex === 'F' ? RT.sexF : subject.sex === 'Other' ? RT.sexOther : RT.sexNone;
  const quality = `${Math.round((result.cleanEpochs / Math.max(1, result.totalEpochs)) * 100)}%`;

  return {
    lang,
    subjectInfo: {
      reportId,
      id:            subject.id  || '—',
      name:          subject.name || '—',
      age:           `${result.age}${RT.ageSuffix}`,
      sex:           sexLabel,
      recordingDate: `${rec.getFullYear()}/${pad2(rec.getMonth()+1)}/${pad2(rec.getDate())} ${pad2(rec.getHours())}:${pad2(rec.getMinutes())}:${pad2(rec.getSeconds())}`,
      quality,
      generatedDate: `${now.getFullYear()}/${pad2(now.getMonth()+1)}/${pad2(now.getDate())} ${pad2(now.getHours())}:${pad2(now.getMinutes())}:${pad2(now.getSeconds())}`,
    },
    brainIndices,
    capabilityProfile: effectiveCapability,
    ageGroupLabel,
    ageNotApplicable,
    summary: {
      abnormalNames: abnormal.map(b => b.id),
      goodNames:     good.map(b => b.id),
    },
    topSupps,
    topFlowers,
    rppg,
  };
}

// ---------------------------------------------------------------------------
// Public API — opens the report in a new tab
// ---------------------------------------------------------------------------

function buildFullHtml(reportId: string, htmlBody: string, lang: ReportLang = 'zh-TW'): string {
  const RT = REPORT_TEXT[lang];
  return `<!DOCTYPE html>
<html lang="${RT.htmlLang}">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1.0"/>
  <title>${RT.reportTitle} — ${reportId}</title>
  <script src="https://cdn.tailwindcss.com"></script>
</head>
<body>
${htmlBody}
<script>
  document.getElementById('printBtn')?.addEventListener('click', function(){ window.print(); });
</script>
</body>
</html>`;
}

export async function openHtmlReport(
  result: ReportResult,
  subject: SubjectInfo,
  startTime: Date | null,
  deviceId: string | null,
  rppg?: RppgResults,
  lang: ReportLang = 'zh-TW',
): Promise<void> {
  const props = buildReportProps(result, subject, startTime, deviceId, rppg, lang);

  // Open the window IMMEDIATELY (must be synchronous w.r.t. user gesture to pass popup blocker)
  const win = window.open('', '_blank');
  if (win) {
    win.document.write('<html><body style="background:#0a1422;color:#8ba3c8;font-family:sans-serif;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;font-size:16px">報告生成中，請稍候…</body></html>');
    win.document.close();
  }

  // Try to upload the HTML and get a shareable URL for the QR code
  let qrCodeDataUrl: string | undefined;
  try {
    const prelimBody = ReactDOMServer.renderToStaticMarkup(<EegReportTemplate {...props} />);
    const prelimHtml = buildFullHtml(props.subjectInfo.reportId, prelimBody, lang);
    const resp = await fetch(REPORT_API, {
      method: 'POST',
      headers: { 'Content-Type': 'text/html' },
      body: new Blob([prelimHtml], { type: 'text/html;charset=utf-8' }),
    });
    if (resp.ok) {
      const { url } = await resp.json() as { url: string };
      qrCodeDataUrl = await QRCode.toDataURL(url, { width: 400, margin: 2, errorCorrectionLevel: 'M', color: { dark: '#000000', light: '#ffffff' } });
    }
  } catch { /* no QR if upload fails */ }

  // Final render with QR code embedded
  const finalProps = { ...props, qrCodeDataUrl };
  const htmlBody = ReactDOMServer.renderToStaticMarkup(<EegReportTemplate {...finalProps} />);
  const fullHtml = buildFullHtml(props.subjectInfo.reportId, htmlBody, lang);

  if (win) {
    // Write final HTML into the already-open window
    win.document.open();
    win.document.write(fullHtml);
    win.document.close();
  } else {
    // Popup was blocked — fallback to blob URL (user may need to allow popups)
    const blob = new Blob([fullHtml], { type: 'text/html;charset=utf-8' });
    const blobUrl = URL.createObjectURL(blob);
    const w2 = window.open(blobUrl, '_blank');
    if (w2) w2.addEventListener('load', () => setTimeout(() => URL.revokeObjectURL(blobUrl), 5000));
    else {
      setTimeout(() => URL.revokeObjectURL(blobUrl), 30000);
      throw new Error('瀏覽器封鎖了彈出視窗，請允許此網站開啟彈出視窗後重試');
    }
  }
}
